INSERT INTO customers (id, application_date, name, email, utm_source, utm_medium, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, purchased_content, sns_accounts, reference_media, hobbies, behavioral_traits, other_background, transfer_intent) VALUES (E'e20a5a91-ab03-410a-8400-830b3ace4c16', E'2026-02-21', E'Yuta Ishizaki', E'y1207i.tora@gmail.com', E'lstep', E'1stdaychuto', E'既卒・中途(7年目以上)', E'2019年に慶應義塾大学経済学部を卒業し、東京海上日動火災保険株式会社に入社。7年間で企業営業→新規事業開発→海外駐在を経験。業務詳細は以下の通り。\n1.企業営業（3年）\n大阪に本社を置く化学メーカーやハウスメーカー、FinTech系スタートアップや中堅中小企業を中心に約20社を担当し、保険プログラム新規組成PJTを複数経験。在籍最終年度の2021年度には、企業営業部門の社内表彰制度（役員表彰）にて最優秀賞を受賞。\n2.新規事業開発（3年）\n2021年度に応募した社内新規事業プログラムにて上位3案の優秀賞（グループCEO表彰）を受賞したことをきっかけに、保険外収益の創出をミッションとする新規事業部門へ異動。その後、防災・減災領域の事業戦略策定や各種会議体対応、アライアンス企画、新規サービスパッケージの企画・開発業務に従事。2023年度は事業戦略の推進母体であるグループ会社「東京海上レジリエンス株式会社」の設立を担当し、PMとしてバックオフィス整備をはじめとする設立プロジェクトを完遂。\n3.海外駐在（1年）\n米国ハワイ州ホノルルにて、唯一の日本人としてキャプティブマネジメント業務に従事。日系大企業8社のキャプティブ（注：事業会社がグループ内に設立する保険子会社）のマネジメント業務全般を担い、現地のサービスプロバイダー（注：会計事務所、監査法人、弁護士事務所）と連携しながら決算・税務・監査・取締役会/株主総会運営等を担当。また、キャプティブ新設を検討する企業に対してフィージビリティスタディ（注：予想5ヵ年財務諸表の作成と必要資本金額の算定）やキャプティブ活用コンサルティング、自組織のオペレーション最適化や組織再編を推進中。', E'Youtube', E'y1207i.tora@gmail.com', E'1996-12-07', E'イシザキ　ユウタ', E'マッキンゼー, BCG, ベイン, カーニー, S&, ローランドベルガー, その他戦略コンサル, 総合コンサル（Big4、アクセンチュアなど）', E'初心者：対策を始めたばかりでほぼ初心者', E'関心が高い', E'フェルミ推定の教科書(note)', E'https://x.com/', E'なし', E'野球、テニス、ゴルフ', E'人とは異なる視点や独創的なアイデアを出す力がある, チームをまとめたりリーダーシップを取るのが得意である/好きである, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意', E'米国ハワイ州ホノルル', E'ブティック系も含めた戦略ファームに内定すれば転職したい');
