INSERT INTO customers (id, application_date, name, email, utm_source, attribute, career_history, initial_channel) VALUES (E'4ad165f9-3250-4148-aeca-0004c74ea3fe', E'2026-02-09', E'木村　祐騰', E'yklps3@gmail.com', E'times', E'既卒', E'慶應義塾大学法学部卒業後、2013年に野村不動産株式会社に新卒で入社。法人営業にて7年間、トップマ\nネジメント層に対し企業不動産の活用提案と実行支援に取り組み、全国にある数千万円から数十億円規\n模の工場・倉庫・オフィスビル等の処分及び活用に寄与。\n2020年4月より自社事業（マンション）用地仕入業務を行う部署へ異動。事業用地の探索をはじめ、マー\nケット調査・行政協議・事業推進を行う事業開発業務に従事。事業環境が厳しい中、既存のルールに捉\nわれない用地取得手法を模索し事業創出に尽力。5年間で売上300億円規模の商品開発に貢献した。', E'不明');
