INSERT INTO customers (id, application_date, name, email, phone, utm_source, utm_medium, utm_id, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, target_firm_type, initial_level, program_interest, purchased_content, sns_accounts, reference_media, hobbies, behavioral_traits, transfer_intent) VALUES (E'ce1924d0-3dfd-4d22-954f-74696e047040', E'2026-01-29', E'寺本　健太郎', E'teramin1225@gmail.com', E'9077082424', E'blog', E'fotter', E'【中途】戦コン各社のwebテスト出題状況、攻略・', E'既卒・中途(7年目以上)', E'■学歴\n◆2010年4月 - 2014年3月：東京農工大学 工学部 生命工学科 卒業\n◆2014年4月 - 2016年3月：東京農工大学大学院 工学府 生命工学専攻 修了（修士）\n・専門領域：バイオテクノロジー、微生物学、遺伝子工学、バイオセンサー（創薬・食品分野への応用研究）\n\n■職歴 1. サントリーホールディングス株式会社（2016年4月 - 2024年5月）\n◆職種： 研究開発・品質保証（R&D）／グループ品質本部 安全科学センター プロジェクトリーダー\n◆主な業務内容：\n・グローバル品質課題の解決・技術開発:\n海外工場（ベトナム等）で発生した微生物汚染トラブルに対し、プロジェクトリーダーとして現地に赴き、新規検出技術の開発から実装までを主導。年間約5億円の廃棄損失を回避し、トラブルを完全解決（サントリーグループ表彰受賞）。\n・新技術の全社導入・標準化:\n食品業界初となる「質量分析計を用いたカビ迅速同定法」を開発・実装。検査時間を大幅に短縮し、機会損失を約1億円/件削減。全社標準技術として国内工場へ展開。\n\n2. 株式会社ピー・アンド・イー・ディレクションズ（2024年6月 - 現在）\n職種： シニアコンサルタント（入社10ヶ月でコンサルタント⇒シニアコンサルタントへ早期昇格）\n◆主な業務内容：\n・製造業向けPMI実行支援（Post Merger Integration）：\n投資ファンド傘下の大手鍛造メーカー（国内外4社統合）におけるPMIを実行リードとして推進。\n100日プラン策定からガバナンス設計、生産・営業・調達部門の業務変革（BPR）を一気通貫で支援。MD直下の少数精鋭チームにて、現場オペレーションと経営数値を接続した改革を主導。\n・全社成長戦略・R&D戦略立案：\n大手医療機器メーカー（売上1000億円規模）の中長期R&D戦略立案。技術と事業の橋渡し役として、有望領域（TAM 100億円以上）の特定とロードマップ策定を実施。\n大手消費財メーカー（売上2兆円規模）の事業基盤構築戦略において、クライアントのパーパス起点のKSF導出・評価軸策定をリード。', E'不明', E'teramin1225@gmail.com', E'1990-12-25', E'テラモト　ケンタロウ', E'マッキンゼー, BCG, ベイン, カーニー, ADL, ローランドベルガー', E'戦略', E'中級：基礎的なインプットが完了し、友人や内定者と面接形式での演習等も開始している', E'関心が高い', E'ケース面接の教科書(note), ケース面接対策動画講座, フェルミ推定の教科書(note), フェルミ動画講座, マッキンゼー内定の教科書(note), マッキンゼー動画講座', E'https://x.com/', E'貴社note、元BCG高松さんの考えるエンジンの本', E'国際交流、一眼レフ', E'知識や経験には自信がないが、思考力や思考スピードには比較的自信がある, 人とは異なる視点や独創的なアイデアを出す力がある, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意', E'外資戦略ファームに内定すれば転職したい（それ以外はしない）');
