INSERT INTO customers (id, application_date, name, email, phone, utm_source, utm_medium, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, target_firm_type, initial_level, program_interest, sns_accounts, reference_media, behavioral_traits, transfer_intent) VALUES (E'6d7a95cc-921c-41c8-81ee-e645d90e2cca', E'2026-01-25', E'大西翔', E'sho.nego.0805@gmail.com', E'070 9136 8625', E'officialline', E'richmenu', E'既卒・中途(7年目以上)', E'【基本情報】\n・1990年8月生まれ（応募時35歳）\n・日本と中国のハーフ\n・幼少期を中国および米国で過ごし、日本の高校卒業後、台湾へ留学\n\n【学歴】\n・国立台湾大学 卒業（2014年）\n　※卒業生総代に選出（日本人初）\nhttps://admissions.ntu.edu.tw/explore/alumni-highlights/ (卒業生の活躍紹介サイト)\n　※体育会バドミントン部に所属し、台湾インカレ男子団体戦で優勝（高校時代は男子ダブルスでジュニアオリンピックに出場）\n\n・米コロンビア大学 国際公共政策大学院（SIPA）修了\n　公共経営学修士（金融経済専攻）（2021年9月〜2023年6月）\n\n・独ヘルティ行政大学院 修了\n　国際関係論修士（安全保障専攻）（2021年9月〜2023年6月）\n　※コロンビア大学とのダブルディグリープログラム（学内選考通過）\n　※日本人会の初代会長\n\n【職歴】\n・三菱UFJ銀行\n　上本町支店 (大阪)•法人取引（2014年7月〜2017年11月）\n　大阪本部•貿易外為取引\n　調査役（課長補佐級）（2017年11月〜2021年7月）\n\n・EYパルテノン（外資系戦略コンサル）\n　金融事業部（M&AビジネスDD）\n　シニアコンサルタント（2023年7月〜2024年3月）\n\n・JPモルガン（外資系金融機関）\n　法人/投資銀行部門・決済事業部\n　アソシエイト（2024年3月〜2024年6月）\n\n・内閣府\n　規制改革推進室•働き方／人への投資WG事務局 (労働/教育チーム)\n　参事官補佐（課長補佐級）（2024年7月〜現在）\n\nhttps://www.cao.go.jp/about/doc/about_pmf.pdf (P14-15)\n\n　※河野太郎大臣→平将明大臣→城内実大臣にお仕えし、チームリーダーとして総括業務を担いながら、チームの成果の約半分(6件)を1人で実現(成約)。\n\n　※例年、課長補佐級が実現(成約)に至る案件は年間平均2件であり、もし私がチームリーダーとして0.5人分のリソースを総括業務に割かなくてよく個別案件に注力できる環境であれば、単純計算で12件(1人あたり年間平均の6倍)を実現(成約)したことになる。\n\nhttps://www8.cao.go.jp/kisei-kaikaku/kisei/publication/opinion/250528.pdf (P55-70)\n\nhttps://www8.cao.go.jp/kisei-kaikaku/kisei/publication/p_report.html (令和7年5月28日)\n\n【資格】\nM&Aシニアエキスパート、防災士、介護福祉士実務者研修、外国人雇用労務士、産業廃棄物適正能力検定基礎編、金融業務能力検定(財務、税務、法務、事業承継•M&A)、普通自動車第一種免許etc.\n\n【語学】\n・中国語：HSK6級、HSKK高級、TOCFL精通級（いずれも最上級）\n・英語：TOEFL iBT 108点', E'Google検索', E'sho.nego.0805@gmail.com', E'1990-08-05', E'オオニシ　ショウ', E'マッキンゼー, BCG, ベイン', E'戦略', E'中級：基礎的なインプットが完了し、友人や内定者と面接形式での演習等も開始している', E'関心が高い(他サービスと比較中)', E'https://x.com/', E'Youtube', E'スポーツや芸術・学業などで卓越した実績を上げた経験がある, チームをまとめたりリーダーシップを取るのが得意である/好きである', E'外資戦略ファームに内定すれば転職したい（それ以外はしない）');
