INSERT INTO customers (id, application_date, name, email, attribute, career_history, initial_channel, birth_date, target_companies, initial_level, application_reason_karte, program_interest, reference_media, behavioral_traits, transfer_intent) VALUES (E'c591b411-2556-46ab-8029-2dd69ff91d6a', E'2026-01-18', E'上田　莉奈', E'rinaueda3@gmail.com', E'既卒・中途(3年目以上7年目未満)', E'【学歴】\n2018年3月　東京工業大学　環境・社会理工学院　土木・環境工学系　卒業\n2020年3月　東京工業大学　環境・社会理工学院　土木・環境工学系　終了\n（2018.7-2019.7  オーストラリア　メルボルン大学　交換留学）\n\n【職歴】\n2020年４月ー現在　日本工営株式会社\n東京工業大学大学院環境・社会理工学院を修了後、2020年4月に日本工営株式会社に入社。入社後の国内2年間は、官公庁・自治体向けに都市・交通分野のコンサルティングに従事し、地方都市の路線バス再編（減便・系統再編、補助制度を踏まえたネットワーク再設計）を中心に、利用実態データ分析、再編効果の定量化、交通事業者・自治体との協議・合意形成、計画策定を担当。あわせて、自動運転・MaaS等の実証プロジェクトにも参画し、実証の企画設計から効果検証・実装に向けた検討を行った。\n2022年4月より海外部署に異動し、JICAや官公庁・民間企業をクライアントとする海外コンサルティングを3年3か月経験。自動運転・MaaS・モビリティサービス実証、都市計画、震災復興計画等のプロジェクトに従事した。データ分析、関係者調整、プロジェクト推進力を強みとし、東南アジアの自動運転実証やモビリティサービス実証では多国籍チームを率いてプロジェクトマネジメントを実施し実証を成功に導く。\n2025年7月より同社の国内事業の部署に異動し、自動運転・MaaS実証プロジェクト、地域公共交通計画策定など交通・都市計画分野の官公庁・自治体案件に取り組む。', E'X', E'1996-01-02', E'マッキンゼー, BCG, ベイン, カーニー', E'初級：書籍等でインプットはある程度完了したが、面接形式での演習等は出来ていない', E'Xでの発信を読んで', E'関心が高い', E'特にありません', E'知識や経験には自信がないが、思考力や思考スピードには比較的自信がある, チームをまとめたりリーダーシップを取るのが得意である/好きである, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意', E'外資戦略ファームに内定すれば転職したい（それ以外はしない）');
