INSERT INTO customers (id, application_date, name, email, phone, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, target_firm_type, initial_level, program_interest, sns_accounts, reference_media, hobbies, behavioral_traits, other_background, transfer_intent) VALUES (E'd36be7e8-b8e7-4351-a54a-35dcd4beaebb', E'2026-01-11', E'松房真之介', E'zacceydesuyo@gmail.com', E'818015635751', E'既卒・中途(7年目以上)', E'学歴\n沼津工業高等専門学校 電子制御工学科 (2012年入学、2017年卒業)\n豊橋技術科学大学 工学部 機械工学課程 (2017年3年次編入、2019年卒業)\n\n職歴\n株式会社アイデミー (2019年8月〜現在)\n- 役割：\n    - Data&AI 部、データサイエンティスト\n    - Data&AI 部部長 (2025年6月〜)\n- 業務内容/実績:\n    - 大手企業向けのAI導入やデータ分析プロジェクトにおける、提案、仮説検証、実装を全般的に担当\n    - 10名以下の規模のチームマネジメント', E'Google検索', E'zacceydesuyo@gmail.com', E'1996-06-21', E'マツフサ　シンノスケ', E'総合コンサル（Big4、アクセンチュアなど）', E'総合', E'初心者：対策を始めたばかりでほぼ初心者', E'関心が高い', E'https://x.com/', E'特になし', E'趣味\n・ドライブ\n・子供と遊ぶこと\n・読書\n\n特技\n・データ分析・AI活用に関すること全般\n・体を動かすこと全般\n・数字80桁を60秒以内に暗記できること', E'人とは異なる視点や独創的なアイデアを出す力がある, ビジネス・企業に関心がありビジネス系の知識には比較的自信がある, 起業したり・自分で事業をやった経験がある（小規模でもok）, チームをまとめたりリーダーシップを取るのが得意である/好きである, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意', E'戦略コンサルタントへ直接のジョブチェンジは、現状を考えると筋が少し悪いと思い、希望はいたしません。\n既存のスキルセットや経験（データサイエンティスト・チームマネジメント等）を主軸としつつ、その付加価値として、キャリアアップに繋がる能力として、ケース面接的な能力（論理思考、素早く考えをまとめて話す訓練、幅広いビジネス分野の知見収集）を身につけることが得策と考えて、応募いたしました。\n\n既出情報ですが、現職企業 (株式会社アイデミー) がアクセンチュアの子会社となっており、今後統合が進んでいく状況です。その中で総合・戦略のコンサルタントの方とお話しする機会が増えており、彼らの思考をより解像度高く理解する訓練となれば幸いです。', E'現職よりも良い待遇が得られる可能性があれば検討したい。');
