INSERT INTO customers (id, application_date, name, email, attribute, career_history, initial_channel, birth_date, target_companies, initial_level, application_reason_karte, program_interest, purchased_content, parent_support, reference_media, hobbies, behavioral_traits) VALUES (E'49da751c-7ddb-4e0b-aa6c-b0d0e821265d', E'2026-01-09', E'有馬　秀一', E'arishu1031@gmail.com', E'28卒(学部卒)', E'【受講コース・学業】\n東京大学 経済学部 経営学科: 組織行動論や組織構造論を専攻。「組織はいかにして学習するか」という経営メカニズムを理論的に学習。\n東京大学 松尾・岩澤研究室提供講座: 「GCI（データサイエンス）」および「大規模言語モデル講座」を修了し、AIの数理的背景と実装技術を習得。\n【プロジェクト経験】\n・AIベンチャーでの長期インターン\n職人知見クラウドの開発:Difyを活用し、熟練職人の属人的な「暗黙知」をAIワークフローとして「形式知」化するシステムを構築。開発の難しさを通じて、大学の経営学で学んだ「組織知の循環」や「非公式組織の重要性」を実務レベルで再発見し、深い理解を得ました。\n業務自動化と意思決定支援: 音響解析業務において、ローコードの限界に対しPython実装への転換を主導。ROI（投資対効果）試算を行い、予算獲得と開発前倒しを実現しました。また、AI研修講師として、長期インターン先のイベントにて、生成AIの信頼性（グラウンディング）やAIツールの活用法を指導し、技術普及に従事した。', E'X', E'2004-06-14', E'BCG', E'初心者：対策を始めたばかりでほぼ初心者', E'公式LINEからのメッセージを読んで', E'関心はあまりない', E'フェルミ推定の教科書(note)', E'支援を受ける予定はない', E'特になし', E'・ダンス\n・ゲーム\n・哲学\n・AI\n・データサイエンス', E'知識や経験には自信がないが、思考力や思考スピードには比較的自信がある, ビジネス・企業に関心がありビジネス系の知識には比較的自信がある, 長期インターンの経験がある（新卒の方向け）');
