INSERT INTO customers (id, application_date, name, email, attribute, career_history, initial_channel, birth_date, target_companies, initial_level, application_reason_karte, program_interest, parent_support, reference_media, hobbies, behavioral_traits) VALUES (E'44ccd746-d322-48c1-94e9-a4859f3652b6', E'2026-01-07', E'安達　真斗', E'1048596@keio.jp', E'28卒(院卒)', E'慶應義塾大学理工学部生命情報学科四年\n慶應義塾大学院理工学研究科基礎理工学専攻声明システム情報専修　進学予定。', E'X', E'2003-04-17', E'マッキンゼー, BCG, ベイン, カーニー', E'初心者：対策を始めたばかりでほぼ初心者', E'Xでの発信を読んで', E'関心が高い(他サービスと比較中)', E'必要があれば依頼できる', E'Aces', E'合気道。大学から初めて体育会の部活に入って4年間やってました。全国大会入賞経験あり。合気道の本とか武道の研究論文読むのも好きでした。これに関連して、分子細胞生物学の本や解剖学の本などを読み、武道の動きをしている際に、実際にどのようなことが生体で起きてるのか考えるのが好きでした。\nまた、研究者の本を読むことも好きでした。自然科学の研究者の本を読むことで、人類知の最先端がどのようなものか、またどのようにしてその考えに辿り着いたのかを知れて楽しいです。\n一番面白かった本は、古澤明という研究者の「光の量子コンピュータ」という本です。量子の中でも光に注目した理由が、日本や日本人の強みに繋がってくること、また歴史的大発見をした際の発想が趣味のサーフィンから生まれてきたことなどが面白かったです。「光の気持ちになって考える」ことで、新たな知見を得られたという、非常にユニークな経験に、結果を出す人のエッセンスが詰まっていると感じました。', E'人とは異なる視点や独創的なアイデアを出す力がある, スポーツや芸術・学業などで卓越した実績を上げた経験がある, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意');
