INSERT INTO customers (id, application_date, name, email, phone, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, purchased_content, sns_accounts, reference_media, hobbies, behavioral_traits, transfer_intent, university) VALUES (E'12639ca8-ba08-40b3-8aa1-eeba146863f0', E'2025-11-07', E'高田　大輝', E'hirokitakadabusi@gmail.com', E'8040624910', E'既卒・中途(7年目以上)', E'2017年　慶應義塾大学総合政策学部卒\n2017年　住友商事建設機械事業本部入社\n1年目は国内の新規事業開発および営業活動を担当。\n2年目以降は、東南アジア向け産業車両事業の出資先における事業再生に従事し、2年半での黒字転換を実現。ポートフォリオ再構築、営業オペレーション刷新、販売戦略再設計、人事制度改定、一部従業員整理など、ハンズオンでの事業改革を主導。\n並行してトレード業務にも従事し、仕入・販売計画策定、日系大手メーカー（T社、K社等）との仕入計画・価格交渉等についての折衝を担当。\n\n2021年　輸送機建機経理部\n輸送機部門の管理会計および財務経理を担当。事業会社の予算策定・KPI構築支援、税務調査対応、CFO向けレポーティング、IR対応、株主総会関連業務など、コーポレート担当として、経営基盤を支える各種管理業務・ガバナンス強化を幅広く支援。\nまた、事業会社売却において財務モデリングおよびFA（フィナンシャルアドバイザー）との調整を担当し、データ整理からバリュエーション、交渉プロセス支援まで実務を経験。\n\n2024年　戦略・企画グループ\n自動車・モビリティ領域の戦略企画を担当。グループ全体のポートフォリオマネジメントおよび事業戦略立案をリードし、CEOレベルの意思決定支援を実施。\n加えて、個別事業ラインにおけるリスク・投融資審査、自動車グループ傘下35社の事業計画策定支援、KPI設計・モニタリングなど、ガバナンスと経営管理の高度化を推進。\nさらに、自動車・モビリティ関連の投融資・M&A案件において、戦略検討、財務モデル構築、BDD対応など一連の投資実務に広範に関与し、案件の価値評価・投資判断プロセスを牽引。', E'Google検索', E'hirokitakadabusi@gmail.com', E'1993-04-06', E'タカダ　ヒロキ', E'マッキンゼー, BCG, ベイン, カーニー, S&, ADL, ローランドベルガー, その他戦略コンサル', E'初級：書籍等でインプットはある程度完了したが、面接形式での演習等は出来ていない', E'関心が高い', E'ケース面接の教科書(note), ケース面接対策動画講座, フェルミ推定の教科書(note), フェルミ動画講座, マッキンゼー内定の教科書(note), マッキンゼー動画講座', E'https://x.com/', E'FactLogic', E'テニス・運動。\n最近は2人の子供を連れて良く近所のプールで週末過ごします。', E'人とは異なる視点や独創的なアイデアを出す力がある, チームをまとめたりリーダーシップを取るのが得意である/好きである', E'外資戦略ファームに内定すれば転職したい（それ以外はしない）', E'慶應義塾大学');
