INSERT INTO customers (id, application_date, name, email, phone, utm_source, utm_medium, utm_id, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, sns_accounts, reference_media, hobbies, transfer_intent, university) VALUES (E'b0e97b3f-75b6-4aa6-bf5e-eac21c23f335', E'2025-10-07', E'藪　颯人', E'hayato68@yahoo.com', E'8086928997', E'facebook', E'cpc', E'120227415426960455', E'既卒・中途(3年目以上7年目未満)', E'名古屋大学医学部保健学科放射線技術科学専攻/東京海上日動火災保険株式会社\n【職務概要】\n2020年に名古屋大学卒業後、東京海上日動火災保険株式会社に新卒入社し、国内外の拠点にて代理店販売支援・新規開拓・地場大企業への経営課題解決提案に従事。入社後3年間は愛知県でプライム上場企業名古屋支店・ディーラー・地場大手の自動車整備工場（モーター）を主な担当として、損害保険・生命保険の代理店営業・新規開拓営業に従事。2023年には東京海上日動中国有限公司へ駐在員として出向し、新規開拓、日系企業の海外進出支援、支店のマネジメントに従事。2024年以降は広島支店にて地場大企業の各部署(経営・人事・管理・営業)に対して継続的な訪問を行い、IR資料の分析に基づく経営課題の仮説立案から課題解決に向けた当社グループや社外の保険やソリューションの提案を実施。入社以降一貫して顧客の事業環境・組織構造両面からの分析に基づき、仮説立案から施策実行、効果検証までを推進してきました。', E'Facebook/インスタグラム', E'hayato68@yahoo.com', E'1997-06-08', E'ヤブ　ハヤト', E'BCG, ベイン, カーニー, S&, ADL, ローランドベルガー, その他戦略コンサル, 総合コンサル（Big4、アクセンチュアなど）', E'初級：書籍等でインプットはある程度完了したが、面接形式での演習等は出来ていない', E'関心が少しある', E'https://x.com/', E'リメディのYouTube', E'趣味：ジム、サウナ(週2-3回)、特技：ゴルフ(ベストスコア68)', E'戦略/総合問わずコンサルティングファームに転職したい', E'名古屋大学');
