INSERT INTO customers (id, application_date, name, email, utm_source, utm_medium, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, sns_accounts, reference_media, hobbies, behavioral_traits, transfer_intent, university) VALUES (E'15fbef1f-b9df-42e9-bc8e-037fb86f1312', E'2025-10-01', E'荒木貴裕', E'takahiro.araki.biz@gmail.com', E'lstep', E'1stdaychuto', E'既卒・中途(7年目以上)', E'■東京理科大学　基礎工学部　電子応用工学科　2015年卒業\n■筑波大学大学院　システム応報工学研究科　構造エネルギー工学専攻　2017年修了\n■アビームコンサルティング　2018年4月入社　2021年9月退社（職位：コンサルタント）\n　重工業へのRPA導入、エンタメ業界・出版社へのBPR等\n■株式会社BBSコンサルティング　2021年10月入社　2022年9月退社（職位：シニアコンサルタント）\n　大手通信会社に対する外部環境調査、新規事業策定支援\n■HEROES株式会社　2023年1月設立（一人法人）\n　大手通信会社に対する外部環境調査、新規事業策定支援\n　大手通信会社に対する事業立ち上げ支援\n　電力会社に対するBPR\n　総合電機メーカーに対する営業戦略策定及び伴走支援\n　大手保険会社に対するアプリ開発PMO支援', E'Youtube', E'takahiro.araki.biz@gmail.com', E'1992-07-07', E'アラキ　タカヒロ', E'マッキンゼー, BCG, ベイン, カーニー, S&, ADL, ローランドベルガー, その他戦略コンサル, 総合コンサル（Big4、アクセンチュアなど）', E'初級：書籍等でインプットはある程度完了したが、面接形式での演習等は出来ていない', E'関心が高い(他サービスと比較中)', E'https://x.com/', E'【YouTube】\nケース面接.com【コンサル転職・就活】（https://www.youtube.com/@case_interview/videos）\nコンサルキャリア - CONSULTING CAREER（https://www.youtube.com/@StellarCareers2024）', E'・筋トレが趣味\n　ー解剖学やフォームなどのインプットを行い、目的に合わせたメニューを考えている\n　ー食材ごとのカロリー、栄養価をエクセルに一覧化し、食事管理をしている\n　ー毎朝1時間半程度、週5で実施\n・ゴルフ、スノーボード、ドラムが趣味\n　ーギアの情報などをエクセルに一覧化し、スペックや経験から道具の効果や使用感をイメージして練習や購入に反映している\n・人の心理状態を読み取ることが得意\n　ー表情、声色、動作から相手の心理状態やパーソナリティを読み取ることが得意\n・環境を整えることが好き\n　ー「あとは行動するのみ」といった環境を整えるためにインテリアや趣味の用具、食事内容、生活習慣などを最適化することにはまっている\n・自己理解が得意\n　ーものを買うとき等に、なぜそれを欲しているのか、どのような心理状態なのか、商品・サービスの機能価値/感情価値/資産価値、他にどのような人が欲しており共通点は何かなどを考えることが習慣化している\n　ー様々な状況に対して、自分の心理状態などを認識することが習慣化している', E'人とは異なる視点や独創的なアイデアを出す力がある, ビジネス・企業に関心がありビジネス系の知識には比較的自信がある, チームをまとめたりリーダーシップを取るのが得意である/好きである', E'ブティック系も含めた戦略ファームに内定すれば転職したい', E'東京理科大学');
