INSERT INTO customers (id, application_date, name, email, phone, utm_source, utm_medium, utm_id, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, sns_accounts, reference_media, university) VALUES (E'92b42322-2154-4b29-922f-dfd48da8ffd3', E'2025-08-15', E'金城明香理', E'k.akari.h8.4.8@gmail.com', E'9031992514', E'remind1', E'{adgroupname}_mbb 選考', E'{searchterm}', E'既卒', E'学歴:九州大学医学系学府\n職歴:東京大学医科学研究所附属病院にて学術専門職員として就職。院内研究室にて研究員として再生医療関連製品の研究・開発から製造の業務を実施しながら、臨床検査技師として細胞治療にも一部携わっていた。\n\n2社目でプライマル株式会社に転職。主に大手〜中堅企業のクライアントを対象に、新規事業の伴走支援を実施。複数の新規事業プロジェクトに参画し、企画段階の事業コンセプト設計、仮説検証、ローンチ後の拡販戦略立案・推進まで、幅広いフェーズを経験。\n\n研究をずっと進めていても社会的な実装までに時間がかかる、医療×ビジネス経験\n能力的な向き不向き、研究ってどちらかというと、一つをふかぼる\n\n元々は一回目の転職でもVCを目指していた\n間のstepで何を踏むから、新規事業とかコンサルだったので\nビジネスの経験がなく、いきなり戦略コンサルは難しいかなと思った\nヘルスケアとかにこだわりがあるわけではない', E'Google広告', E'k.akari.h8.4.8@gmail.com', E'1996-04-08', E'キンジョウ　アカリ', E'マッキンゼー, BCG, ベイン, カーニー, S&, ADL, ローランドベルガー, その他戦略コンサル, 総合コンサル（Big4、アクセンチュアなど）', E'初心者：対策を始めたばかりでほぼ初心者', E'関心が高い(他サービスと比較中)', E'https://x.com/', E'特になし', E'九州大学');
