INSERT INTO customers (id, application_date, name, email, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, sns_accounts, reference_media, hobbies, behavioral_traits, other_background, university) VALUES (E'd63e1787-1f5a-45b5-8a13-c666ebd25b46', E'2025-07-10', E'鶴田 明暉', E'tsksaint@gmail.com', E'既卒・中途(7年目以上)', E'【学歴】\n2019年 3月 慶應義塾大学 環境情報学部卒 \n\n【職歴】\n2019年4月－2020年5月　　楽天株式会社\n新規事業である携帯電話を扱うモバイル事業の千葉営業部に配属され、個人、法人、行政に対する提案営業に従事。\n【主な担当業務】\n・\tマーケット、競合分析による営業戦略の立案・実施\n・\t新しい営業資料の作成、運用\n・\tチームメンバー40人のマネジメント\n・\t外国人技術担当者との連携営業・販売戦略立案\n\n2021年1月－現在　　株式会社 LIVE BOARD\n事業会社・広告代理店等のクライアント企業を対象に、広告営業を4年経験。\n【主な担当業務】\n・\t提案営業、販売戦略立案\n・\t広告運用\n・\t効果測定レポーティング\n・\tクライアントへのプレゼンテーション（現場レベルから意思決定層まで）', E'Youtube', E'tsksaint@gmail.com', E'1995-07-07', E'ツルタ トシキ', E'その他戦略コンサル, 総合コンサル（Big4、アクセンチュアなど）', E'中級：基礎的なインプットが完了し、友人や内定者と面接形式での演習等も開始している', E'関心が高い', E'https://x.com/', E'noteやYouTube', E'海外サッカー観戦、クラシック音楽鑑賞、サウナ、ラーメンを食べること', E'チームをまとめたりリーダーシップを取るのが得意である/好きである', E'要望としては、ケース面接の模擬実施を複数回希望しています。\n理由は、エージェントと3回模擬面接をしましたが、個人的にはまだケースの完成度が低いと感じており、面接形式での実践が足りないことを危惧しているためです。\n\nまた、前述の通り、既に7/7（月）から各ファームに書類を出し始めています。\n選考スケジュールがタイトなことが予想されるため、短期間で集中的に受講できることを希望しております。\n\n恐れ入りますが、ご確認のほど、どうぞよろしくお願いいたします。', E'慶應義塾大学');
